  ('judicial-f0899a01-moex-00586', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政救濟之敘述，下列何者錯誤？', '["對於違法行政處分，原則上應提起撤銷訴訟", "對於行政契約之爭議，得提起一般給付訴訟", "對於行政事實行為，得提起一般給付訴訟", "對於都市計畫，因其屬於法規命令之性質，無法提起行政爭訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00587', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '人民無須經訴願決定，而得逕行提起行政訴訟者，下列何者不屬之？', '["雖提起訴願逾3個月訴願機關不為決定者", "已用盡其他相當於訴願之程序者", "作成行政處分程序過程已踐行聽證程序者", "因逾越法定訴願期間而不得提起訴願者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00588', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公務員怠於執行職務之國家賠償責任要件，下列敘述何者錯誤？', '["必須是屬於以保護特定人民利益為目的之法定職務", "相關職務必須是行政機關因裁量權收縮至零而產生作為義務之情形", "怠於執行職務之損害，必須是公務員可得預見者", "受害人民對於公務員怠於執行之職務，必須有公法上請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00589', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政訴訟重新審理制度，下列敘述何者錯誤？', '["因高等行政法院撤銷訴訟判決而受有權利損害之第三人，因非可歸責於自己之事由而未參加訴訟，致不 能提出足以影響判決結果之攻擊防禦方法，得對該確定終局判決聲請重新審理", "聲請行政訴訟重新審理，應於知悉確定判決之日起30日內為之，但自判決確定之日起已逾1年者，不 得聲請", "對行政法院確定判決聲請重新審理，專屬於為判決之原行政法院管轄", "對行政法院確定判決聲請重新審理，原確定判決發生當然停止執行之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00590', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於因公共設施所生之國家賠償責任，依國家賠償法規定，下列敘述何者正確？', '["非國家所有但事實上由行政機關管理之既成道路，因不平整致人民受傷，國家不負賠償責任", "橋樑完工後尚未驗收，但已開放民眾通行，因施工瑕疵致人民受傷，應減輕國家之賠償責任", "人民於開放之山域活動，因落石而受傷，如管理機關於該處已設有危險標示，國家不負賠償責任", "人民於國家風景區內因觀景台毀損而受傷，如於觀景台旁已設有警告，應減輕國家之賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
